-- ----------------------------
-- Table structure for novel
-- ----------------------------
DROP TABLE IF EXISTS `novel`;
CREATE TABLE `novel`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `pen_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `cover_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_title`(`user_id`, `title`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  CONSTRAINT `fk_novel_user` FOREIGN KEY (`user_id`) REFERENCES `app_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 53 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of novel
-- ----------------------------
INSERT INTO `novel` VALUES (1, 1, '人间一梦', '舞江月', '多年以后，面对行刑队的枪口，蔡同林会想起那个因错失奖学金而心灰意冷的下午，班长的关切、死党伯越轻哼着匆匆的小曲，去那座隐匿在荒烟蔓草间的古寺。彼时的他尚未知晓，一次随兴的散心之旅，竟会让他们撞破元世界的疮痍，让他踏上一场漫长如梦的奇幻旅途。那是他们命运的开端，亦是终局：这个世界在此时尚未被权利与虚幻完全吞噬，万物未有名号，而这个曾在草丛间渴望未来的少年与单纯的白纸的萍水相逢，最终都将在枪声响起前，于孤独的归途中看清那被欲望写定的宿命。', 'https://www.canva.cn/design/DAHEZAVM9L4/Gz0DnJCv3LxypONahjvCIg/edit?utm_content=DAHEZAVM9L4&utm_campaign=designshare&utm_medium=link2&utm_source=sharebutton', '2026-03-19 20:07:33', '2026-03-22 20:00:21');
INSERT INTO `novel` VALUES (2, 1, '硅基时代', '舞江月', '我叫陈诚，一个富安城的汽修工，这行在这个机器人遍地走的年代，没什么前途，于是我只好兼职做……枪支走私，我真没想到我会走到这一步……', 'preset:silicon-age', '2026-03-20 18:58:46', '2026-05-31 22:06:38');
INSERT INTO `novel` VALUES (49, 1, '达瓦达瓦', '达挖', '达娃大福娃', '', NULL, NULL);
INSERT INTO `novel` VALUES (52, 1, '擦撒擦 ', '达挖啊d', '达挖的 ', '', NULL, NULL);
INSERT INTO `novel` VALUES (53, 1, '达挖啊', ' 阿瓦达阿瓦', ' 阿瓦达啊挖', '', NULL, NULL);

