  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `gender` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `age` int NULL DEFAULT NULL,
  `appearance` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `background` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `personality` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  `extra` json NULL,
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_novel_name`(`novel_id`, `name`) USING BTREE,
  INDEX `idx_novel_id`(`novel_id`) USING BTREE,
  CONSTRAINT `fk_character_novel` FOREIGN KEY (`novel_id`) REFERENCES `novel` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of novel_character
-- ----------------------------
INSERT INTO `novel_character` VALUES (1, 1, '蔡同林', '男', 17, '有些胖，但经过五天的界外流转探索，已经瘦下来了', '父亲（张真司）：大厂高薪程序员;母亲（蔡菜籽）:检察官;六年前母亲死于一场车祸，五年前父亲被裁员，母亲死后父亲变得早出晚归，不知道在忙些什么', NULL, '{}', '2026-03-19 20:56:13');
INSERT INTO `novel_character` VALUES (3, 1, '明', '男', 5100, '看起来瘦削，但事实上很身体很结实，但这是蒙君的身体，他具体长什么样子已经不可考了。', '在这片天地的文明伊始这个四处流浪的弃儿怎么也想不到他会有这么波澜壮阔的一生', '沉稳', '{\"技能\": \"竹书纪年\"}', '2026-03-23 14:56:34');
INSERT INTO `novel_character` VALUES (5, 1, '齐莲儿', '女', 16, '很健康很完美的身材，容貌几乎从任何角度都跳不出毛病来，170的身高在近现代世界不算矮，甚至比绝大多数男性要高', '在一个古代修仙世界中，因为经受梁朝动乱影响，在军妓营中出生，母亲是富延城周边小地主家的掌上千金，身材姣好，能说会道，面若朱玉，眼似水波，但被叛军攻破后，母亲被军人掳掠到营中，献给叛军中的军官，但因为母亲的刚烈咬下了军官某个器官，被军官气急败坏地赏给手下士兵，在被侵犯了一整天后果不其然怀孕了生下了她，任何人都不知道她的父亲具体是谁，但此时的母亲也已经完全精神失常，只能在军妓营中苦难度日，她也被军妓营中的大龄军妓抚养长大，看着她的母亲被迫终日接客，最终生下了三个孩子，一个弟弟，两个妹妹；5岁那年在季子舟的军队占领富延城之后混入溃军逃走，但最终被明捡到并抚养,', '温婉、坚定、训练有素', '{}', '2026-03-23 16:37:54');
INSERT INTO `novel_character` VALUES (7, 2, '陈诚', '男', 35, '结实，矮壮', '当兵，在军队中见识了开山炸洞，战友被炸死', '敦厚，但喜欢冒险', NULL, NULL);

